    else { io::printfn("  FAIL: second coro entry"); fail++; }

    if (test_suspend_resume()) { io::printfn("  PASS: suspend/resume (generator)"); pass++; }
    else { io::printfn("  FAIL: suspend/resume (generator)"); fail++; }

