    else { io::printfn("  FAIL: recursion on separate stack"); fail++; }

    if (test_two_coros_interleaved()) { io::printfn("  PASS: two coros interleaved"); pass++; }
    else { io::printfn("  FAIL: two coros interleaved"); fail++; }

