// --- Test helpers ---

struct TestState {
    int value;
    int step;
}

fn void test_entry_simple(void* arg) {
    TestState* s = (TestState*)arg;
    s.value = 42;
}

fn void test_entry_100(void* arg) {
    TestState* s = (TestState*)arg;
